   140→  return true;
   141→}
   142→
   143→/**
   144→ * Detect initial burst of short garbled lines.
   145→ * Returns the index of the first non-garbled or long line.
   146→ */
   147→function findBurstEnd(lines: Array<{ text: string }>): number {
   148→  let i = 0;
   149→  while (i < lines.length && lines[i].text.length < 20 && isLikelyGarbled(lines[i].text)) {
   150→    i++;
   151→  }
   152→  return i;
   153→}
   154→
   155→function wordCount(text: string): number {
   156→  return text.split(/\s+/).filter((w) => w.length > 0).length;
   157→}
   158→
   159→/**
   160→ * Build candidate strings from lines: single lines plus multi-line joins (2-3 consecutive).
   161→ * Skips initial burst of short garbled lines. Scans all remaining lines. Caps at 25.
   162→ */
   163→function buildCandidates(
   164→  lines: Array<string>
   165→): Array<{ text: string; position: number }> {
   166→  const nonEmptyLines: Array<{ text: string; index: number }> = [];
   167→
   168→  for (let i = 0; i < lines.length; i++) {
   169→    const trimmed = lines[i].trim();
   170→    if (trimmed.length > 0) {
   171→      nonEmptyLines.push({ text: trimmed, index: i });
   172→    }
   173→  }
   174→
   175→  const burstEnd = findBurstEnd(nonEmptyLines);
   176→  const candidates: Array<{ text: string; position: number }> = [];
   177→  const seen = new Set<string>();
   178→
   179→  for (let i = burstEnd; i < nonEmptyLines.length; i++) {
   180→    const line = nonEmptyLines[i];
   181→
   182→    // Single line
   183→    if (passesHardFilters(line.text)) {
   184→      const norm = line.text.toLowerCase();
   185→      if (!seen.has(norm)) {
   186→        seen.add(norm);
   187→        candidates.push({ text: line.text, position: line.index });
   188→      }
   189→    }
   190→
   191→    // 2-line join
   192→    if (i + 1 < nonEmptyLines.length) {
   193→      const joined2 = `${line.text} ${nonEmptyLines[i + 1].text}`;
   194→      if (passesHardFilters(joined2)) {
   195→        const norm = joined2.toLowerCase();
   196→        if (!seen.has(norm)) {
   197→          seen.add(norm);
   198→          candidates.push({ text: joined2, position: line.index });
   199→        }
   200→      }
   201→    }
   202→
   203→    // 3-line join
   204→    if (i + 2 < nonEmptyLines.length) {
   205→      const joined3 = `${line.text} ${nonEmptyLines[i + 1].text} ${nonEmptyLines[i + 2].text}`;
   206→      if (passesHardFilters(joined3)) {
   207→        const norm = joined3.toLowerCase();
   208→        if (!seen.has(norm)) {
   209→          seen.add(norm);
   210→          candidates.push({ text: joined3, position: line.index });
   211→        }
   212→      }
   213→    }
   214→  }
   215→
   216→  // Pre-filter to 25 before embedding calls: prefer ALL_CAPS and short candidates.
   217→  // Position-based scoring handles final ranking.
   218→  if (candidates.length > 25) {
   219→    const prioritized = candidates.slice().sort((a, b) => {
   220→      const aAllCaps = isAllCaps(a.text) ? 0 : 1;
   221→      const bAllCaps = isAllCaps(b.text) ? 0 : 1;
   222→      if (aAllCaps !== bAllCaps) return aAllCaps - bAllCaps;
   223→      const aShort = wordCount(a.text) <= 5 ? 0 : 1;
   224→      const bShort = wordCount(b.text) <= 5 ? 0 : 1;
   225→      return aShort - bShort;
   226→    });
   227→    return prioritized.slice(0, 25);
   228→  }
   229→
   230→  return candidates;
   231→}
   232→
   233→// Module-level cache for reference embeddings
   234→let cachedTitleRefEmbedding: Array<number> | null = null;
   235→let cachedHeaderRefEmbedding: Array<number> | null = null;
   236→let cachedNoiseRefEmbedding: Array<number> | null = null;
   237→
   238→export function _resetEmbeddingCacheForTests(): void {
   239→  cachedTitleRefEmbedding = null;
   240→  cachedHeaderRefEmbedding = null;
   241→  cachedNoiseRefEmbedding = null;
   242→}
   243→
   244→export async function extractTitleWithEmbeddings(
