  for (let i = burstEnd; i < nonEmptyLines.length; i++) {
    const line = nonEmptyLines[i];

    // Single line
    if (passesHardFilters(line.text)) {
      const norm = line.text.toLowerCase();
      if (!seen.has(norm)) {
        seen.add(norm);
        candidates.push({ text: line.text, position: line.index });
      }
