  const isStructuralHeading = (c: { text: string }): boolean => {
    if (!isAllCaps(c.text) || wordCount(c.text) < 2) return false;
    const sigWords = c.text.trim().split(/\s+/).filter((w) => w.replace(/[^A-Z]/g, "").length > 1);
